// Copyright 2009 The Go Authors. All rights reserved.// Use of this source code is governed by a BSD-style// license that can be found in the LICENSE file.// DragonFly BSD system calls.// This file is compiled as ordinary Go code,// but it is also input to mksyscall,// which parses the //sys lines and generates system call stubs.// Note that sometimes we use a lowercase //sys name and wrap// it in our own nicer implementation, either here or in// syscall_bsd.go or syscall_unix.go.package uniximport ("sync""unsafe")// See version list in https://github.com/DragonFlyBSD/DragonFlyBSD/blob/master/sys/sys/param.hvar (osreldateOnce sync.Onceosreldate     uint32)// First __DragonFly_version after September 2019 ABI changes// http://lists.dragonflybsd.org/pipermail/users/2019-September/358280.htmlconst _dragonflyABIChangeVersion = 500705 supportsABI(vint32) bool {osreldateOnce.Do(() { osreldate, _ = SysctlUint32("kern.osreldate") })return osreldate >= ver}// SockaddrDatalink implements the Sockaddr interface for AF_LINK type sockets.type SockaddrDatalink struct {Len    uint8Family uint8Index  uint16Type   uint8Nlen   uint8Alen   uint8Slen   uint8Data   [12]int8Rcf    uint16Route  [16]uint16raw    RawSockaddrDatalink anyToSockaddrGOOS(fd int, rsa *RawSockaddrAny) (Sockaddr, error) {return nil, EAFNOSUPPORT// Translate "kern.hostname" to []_C_int{0,1,2,3}. nametomib(name string) (mib []_C_int, err error) {const siz = unsafe.Sizeof(mib[0])// NOTE(rsc): It seems strange to set the buffer to have// size CTL_MAXNAME+2 but use only CTL_MAXNAME// as the size. I don't know why the +2 is here, but the// kernel uses +2 for its own implementation of this tion.// I am scared that if we don't include the +2 here, the kernel// will silently write 2 words farther than we specify// and we'll get memory corruption.var buf [CTL_MAXNAME + 2]_C_intn := uintptr(CTL_MAXNAME) * sizp := (*byte)(unsafe.Pointer(&buf[0]))bytes, err := ByteSliceFromString(name)if err != nil {return nil, err}// Magic sysctl: "setting" 0.3 to a string name// lets you read back the array of integers form.if err = sysctl([]_C_int{0, 3}, p, &n, &bytes[0], uintptr(len(name))); err != nil {turn nil, err}return buf[0 : n/siz], nil} direntIno(buf []byte) (uint64, bool) {return readInt(buf, unsafe.Offsetof(Dirent{}.Fileno), unsafe.Sizeof(Dirent{}.Fileno))} direntReclen(buf []byte) (uint64, bool) {len, ok := direntNamlen(buf)if !ok {return 0, false}return (16 + namlen + 1 + 7) &^ 7, true} direntNamlen(buf []byte) (uint64, bool) {return readInt(buf, unsafe.Offsetof(Dirent{}.Namlen), unsafe.Sizeof(Dirent{}.Namlen))}//sysnbpipe() (r int, w int, err error) Pipe(p []int) (err error) {if len(p) != 2 {return EINVAL}w, err := pipe()if err == nil {p[0], p[1] = r, w}return}//sysnbpipe2(p *[2]_C_int, flags int) (r int, w int, err error) Pipe2(p []int, flags int) (err error) {if len(p) != 2 {return EINVAL}var pp [2]_C_int// pipe2 on dragonfly takes an fds array as an argument, but stillreturns the file descriptors.r, w, err := pipe2(&pp, flags)if err == nil {p[0], p[1] = r, w}return err//sysextpread(fd int, p []byte, flags int, offset int64) (n int, err error) pread(fd int, p []byte, offset int64) (n int, err error) {return extpread(fd, p, 0, offset)}//sysextpwrite(fd int, p []byte, flags int, offset int64) (n int, err error) pwrite(fd int, p []byte, offset int64) (n int, err error) {return extpwrite(fd, p, 0, offset)} Accept4(fd, flags int) (nfd int, sa Sockaddr, err error) {var rsa RawSockaddrAnyvar len _Socklen = SizeofSockaddrAnynfd, err = accept4(fd, &rsa, &len, flags)if err != nil {return}len > SizeofSockaddrAny {panic("RawSockaddrAny too small")}sa, err = anyToSockaddr(fd, &rsa)if err != nil {Close(nfd)nfd = 0}return}//sysGetcwd(buf []byte) (n int, err error) = SYS___GETCWD Getfsstat(buf []Statfs_t, flags int) (n int, err error) {var _p0 unsafe.Pointervar bufsize uintptrif len(buf) > 0 {_p0 = unsafe.Pointer(&buf[0])bufsize = unsafe.Sizeof(Statfs_t{}) * uintptr(len(buf))r0, _, e1 := Syscall(SYS_GETFSSTAT, uintptr(_p0), bufsize, uintptr(flags))n = int(r0)if e1 != 0 {err = e1}return}//sysioctl(fd int, req uint, arg uintptr) (err error)//sysioctlPtr(fd int, req uint, arg unsafe.Pointer) (err error) = SYS_IOCTL//syssysctl(mib []_C_int, old *byte, oldlen *uintptr, new *byte, newlen uintptr) (err error) = SYS___SYSCTL sysctlUname(mib []_C_int, old *byte, oldlen *uintptr) error {err := sysctl(mib, old, oldlen, nil, 0)if err != nil {// Utsname members on Dragonfly are only 32 bytes and// the syscall returns ENOMEM in case the actual value// is longer.if err == ENOMEM {err = nil}}return err} Uname(uname *Utsname) error {mib := []_C_int{CTL_KERN, KERN_OSTYPE}n := unsafe.Sizeof(uname.Sysname)if err := sysctlUname(mib, &uname.Sysname[0], &n); err != nil {return err}uname.Sysname[unsafe.Sizeof(uname.Sysname)-1] = 0mib = []_C_int{CTL_KERN, KERN_HOSTNAME}n = unsafe.Sizeof(uname.Nodename)if err := sysctlUname(mib, &uname.Nodename[0], &n); err != nil {return err}uname.Nodename[unsafe.Sizeof(uname.Nodename)-1] = 0mib = []_C_int{CTL_KERN, KERN_OSRELEASE}n = unsafe.Sizeof(uname.Release)if err := sysctlUname(mib, &uname.Release[0], &n); err != nil {return err}uname.Release[unsafe.Sizeof(uname.Release)-1] = 0mib = []_C_int{CTL_KERN, KERN_VERSION}n = unsafe.Sizeof(uname.Version)if err := sysctlUname(mib, &uname.Version[0], &n); err != nil {return err}// The version might have newlines or tabs in it, convert them to// spaces.for i, b := range uname.Version {if b == '\n' || b == '\t' {if i == len(uname.Version)-1 {uname.Version[i] = 0 else {uname.Version[i] = ' '}}}mib = []_C_int{CTL_HW, HW_MACHINE}n = unsafe.Sizeof(uname.Machine)if err := sysctlUname(mib, &uname.Machine[0], &n); err != nil {return err}uname.Machine[unsafe.Sizeof(uname.Machine)-1] = 0return nil} Sendfile(outfd int, infd int, offset *int64, count int) (written int, err error) {if raceenabled {raceReleaseMerge(unsafe.Pointer(&ioSync))}return sendfile(outfd, infd, offset, count)}/* * Exposed directly *///sysAccess(pa